   function  computeHistogram ()  {  const  x1  =  [];  const  x2  =  [];  const  y1  =  [];  const  y2  =  [];  let  k  =  0 ;  for  ( let  i  =  1 ;  i  &lt;  500 ;  i ++ )  {  k  =  Math . random ();  x1 . push ( k  *  5 );  x2 . push ( k  *  10 );  y1 . push ( k );  y2 . push ( k  *  2 );  }  const  trace1  =  {  x :  x1 ,  y :  y1 ,  name :  &#39;control&#39; ,  autobinx :  false ,  histnorm :  &#34;count&#34; ,  marker :  {  color :  &#34;rgba(255, 100, 102, 0.7)&#34; ,  line :  {  color :  &#34;rgba(255, 100, 102, 1)&#34; ,  width :  1  }  },  opacity :  0.5 ,  type :  &#34;histogram&#34; ,  xbins :  {  end :  2.8 ,  size :  0.06 ,  start :  . 5  }  };  const  trace2  =  {  x :  x2 ,  y :  y2 ,  autobinx :  false ,  marker :  {  color :  &#34;rgba(100, 200, 102, 0.7)&#34; ,  line :  {  color :  &#34;rgba(100, 200, 102, 1)&#34; ,  width :  1  }  },  name :  &#34;experimental&#34; ,  opacity :  0.75 ,  type :  &#34;histogram&#34; ,  xbins :  {  end :  4 ,  size :  0.06 ,  start :  - 3.2  }  };  return  {  &#34;kind&#34; :  {  &#34;plotly&#34; :  true  },  &#34;data&#34; :  [ trace1 ,  trace2 ],  &#34;layout&#34; :  {  bargap :  0.05 ,  bargroupgap :  0.2 ,  barmode :  &#34;overlay&#34; ,  title :  &#34;Sampled Results&#34; ,  xaxis :  {  title :  &#34;Value&#34;  },  yaxis :  {  title :  &#34;Count&#34;  }  }  }; } let  example3  =  computeHistogram ();
